1	// Proxy-first discovery
2	//
3	// 优先级：
4	//   1. 从 traffic.jsonl 扫描 kind=response 的 /v1/messages 记录（含 reqBody）
5	//   2. 对每条 proxy record 尝试找对应 JSONL session
6	//   3. JSONL-only sessions 仅进入 inventory，不进入主流程
7	
8	import { existsSync, readFileSync, readdirSync } from "node:fs";
9	import { join, resolve, dirname, basename } from "node:path";
10	import { homedir } from "node:os";
11	import { createReadStream } from "node:fs";
12	import { createInterface } from "node:readline";
13	import { queryKeyHash } from "./paths";
14	import type { AgentKind } from "../types";
15	import type {
16	  DiscoveredJsonlSession,
17	  DiscoveredProxyRecord,
18	  DiscoveryResult,
19	  QueryKey,
20	} from "./types";
21	
22	// Claude JSONL 默认存放路径
23	const CLAUDE_PROJECTS_DIR = join(homedir(), ".claude", "projects");
24	// proxy traffic.jsonl
25	const TRAFFIC_LOG = join(homedir(), ".api-dashboard", "proxy", "traffic.jsonl");
26	
27	// fixture 测试模式：从 server/test/fixtures/context-reconstruction 加载
28	// import.meta.dir = server/src/context-ledger/audit → 走 3 级到 server/ → test/...
29	const FIXTURE_BASE = resolve(
30	  import.meta.dir,
31	  "../../../test/fixtures/context-reconstruction",
32	);
33	export const VALID_FIXTURE_NAMES = [
34	  "single-tool-call",
35	  "large-tool-output",
36	  "multi-turn-human",
37	  "system-tools-overhead",
38	];
39	
40	// ─────────────────────────────────────────────────────────────────────────────
41	// 辅助：从 traffic record 提取 session ID
42	// ─────────────────────────────────────────────────────────────────────────────
43	
44	function extractSessionIdFromHeaders(headers: Record<string, string> | undefined): string | null {
45	  if (!headers) return null;
46	  // Claude Code 注入的 session header（大小写不敏感查找）
47	  for (const [k, v] of Object.entries(headers)) {
48	    if (k.toLowerCase() === "x-claude-code-session-id" && v) return v;
49	  }
50	  return null;
51	}
52	
53	function detectAgentKind(headers: Record<string, string> | undefined): AgentKind {
54	  if (!headers) return "unknown";
55	  const ua = headers["User-Agent"] || headers["user-agent"] || "";
56	  if (ua.includes("claude-cli") || ua.includes("claude-code")) return "claude-code";
57	  if (ua.includes("codex")) return "codex";
58	  return "unknown";
59	}
60	
61	// ─────────────────────────────────────────────────────────────────────────────
62	// 核心：扫描 traffic.jsonl 提取 proxy records
63	// ─────────────────────────────────────────────────────────────────────────────
64	
65	// 枚举 traffic.jsonl 及同目录下所有 rotation 文件（traffic.jsonl.<timestamp>）
66	// 按文件名排序（rotation 文件名含 ISO 时间戳，字典序 = 时间序）
67	function listTrafficFiles(trafficFile: string): string[] {
68	  const dir = dirname(trafficFile);
69	  const base = basename(trafficFile);
70	  const files: string[] = [];
71	
72	  if (!existsSync(dir)) return [];
73	
74	  // rotation 文件：base.<timestamp>，如 traffic.jsonl.2026-05-01T07-11-35-020Z
75	  const rotated = readdirSync(dir)
76	    .filter((f) => f.startsWith(base + ".") && f !== base)
77	    .sort()  // ISO timestamp 字典序 = 时间序，旧 → 新
78	    .map((f) => join(dir, f));
79	
80	  files.push(...rotated);
81	
82	  // 当前活跃文件最后读（包含最新记录）
83	  if (existsSync(trafficFile)) files.push(trafficFile);
84	
85	  return files;
86	}
87	
88	// 从单个文件读取 proxy records，返回结果及最大行号（用于 lineNo 去重）
89	async function scanSingleFile(
90	  file: string,
91	  sinceTs: string | undefined,
92	  seenQueryHashes: Set<string>,
93	): Promise<DiscoveredProxyRecord[]> {
94	  const results: DiscoveredProxyRecord[] = [];
95	  let lineNo = 0;
96	
97	  const rl = createInterface({
98	    input: createReadStream(file, { encoding: "utf-8" }),
99	    crlfDelay: Infinity,
100	  });
101	
102	  for await (const line of rl) {
103	    lineNo++;
104	    if (!line.trim()) continue;
105	
106	    let record: Record<string, unknown>;
107	    try {
108	      record = JSON.parse(line) as Record<string, unknown>;
109	    } catch {
110	      continue;
111	    }
112	
113	    // 只处理 kind=response 的 /v1/messages 记录（reqBody 在 response 记录里）
114	    const url = (record["url"] as string | undefined) ?? "";
115	    const kind = record["kind"] as string | undefined;
116	    if (kind !== "response") continue;
117	    if (!url.includes("/v1/messages")) continue;
118	
119	    const reqBodyRaw = record["reqBody"];
120	    if (!reqBodyRaw) continue;
121	
122	    // B1.3: 兼容 base64 编码的 reqBody（proxy 落盘时若是二进制走 base64 分支）
123	    const reqBodyEncoding = (record["reqBodyEncoding"] as string | undefined) ?? "utf8";
124	    let reqBodyText: string | null = null;
125	    if (typeof reqBodyRaw === "string") {
126	      if (reqBodyEncoding === "base64") {
127	        try { reqBodyText = Buffer.from(reqBodyRaw, "base64").toString("utf8"); }
128	        catch { continue; }
129	      } else {
130	        reqBodyText = reqBodyRaw;
131	      }
132	    }
133	
134	    let reqBody: Record<string, unknown>;
135	    try {
136	      reqBody = reqBodyText !== null
137	        ? (JSON.parse(reqBodyText) as Record<string, unknown>)
138	        : (reqBodyRaw as Record<string, unknown>);
139	    } catch {
140	      continue;
141	    }
142	
143	    const ts = (record["ts"] as string | undefined) ?? new Date().toISOString();
144	    const startedAt = (record["startedAt"] as string | undefined) ?? ts;
145	
146	    // sinceTs 过滤
147	    if (sinceTs && ts < sinceTs) continue;
148	
149	    const headers = record["reqHeaders"] as Record<string, string> | undefined;
150	    const sessionId = extractSessionIdFromHeaders(headers) ?? "unknown";
151	    const agentKind = detectAgentKind(headers);
152	
153	    // queryId 使用与 proxy-snapshot-parser 相同的算法
154	    // lineNo 在同一文件内唯一；跨文件用 file+lineNo 组合去重
155	    const tsDigits = startedAt.replace(/[^0-9]/g, "");
156	    const queryId = `query-${tsDigits}-${lineNo}`;
157	    const key: QueryKey = { agentKind, sessionId, queryId };
158	    const hash = queryKeyHash(key);
159	
160	    // 跨 rotation 文件去重：相同 queryId（即相同时间戳+行号）只保留第一次出现
161	    if (seenQueryHashes.has(hash)) continue;
162	    seenQueryHashes.add(hash);
163	
164	    results.push({
165	      queryKey: key,
166	      queryKeyHash: hash,
167	      proxySourceFile: file,
168	      trafficLine: lineNo,
169	      timestamp: startedAt,
170	      sessionId,
171	      agentKind,
172	      raw: { ...record, reqBody },
173	    });
174	  }
175	
176	  return results;
177	}
178	
179	export async function scanProxyRecords(opts?: {
180	  trafficFile?: string;
181	  sinceTs?: string;  // ISO 时间戳，只处理 >= sinceTs 的记录
182	}): Promise<DiscoveredProxyRecord[]> {
183	  const mainFile = opts?.trafficFile ?? TRAFFIC_LOG;
184	  // 扫描主文件 + 所有 rotation 备份（traffic.jsonl.<timestamp>）
185	  const files = listTrafficFiles(mainFile);
186	  if (files.length === 0) return [];
187	
188	  const all: DiscoveredProxyRecord[] = [];
189	  const seenQueryHashes = new Set<string>();
190	
191	  for (const file of files) {
192	    const records = await scanSingleFile(file, opts?.sinceTs, seenQueryHashes);
193	    all.push(...records);
194	  }
195	
196	  // 按 timestamp 升序排列，保持与单文件时相同的时间顺序语义
197	  all.sort((a, b) => a.timestamp.localeCompare(b.timestamp));
198	  return all;
199	}
200	
201	// ─────────────────────────────────────────────────────────────────────────────
202	// 匹配：为每个 proxy record 找对应 JSONL 文件
203	// ─────────────────────────────────────────────────────────────────────────────
204	
205	function findJsonlForSession(sessionId: string): string | null {
206	  if (sessionId === "unknown") return null;
207	
208	  // ~/.claude/projects/<sanitized-path>/<sessionId>.jsonl
209	  // 扫描所有 project 子目录
210	  if (!existsSync(CLAUDE_PROJECTS_DIR)) return null;
211	
212	  const projectDirs = readdirSync(CLAUDE_PROJECTS_DIR, { withFileTypes: true })
213	    .filter((e) => e.isDirectory())
214	    .map((e) => join(CLAUDE_PROJECTS_DIR, e.name));
215	
216	  for (const dir of projectDirs) {
217	    const candidate = join(dir, `${sessionId}.jsonl`);
218	    if (existsSync(candidate)) return candidate;
219	  }
220	
221	  return null;
222	}
223	
224	// ─────────────────────────────────────────────────────────────────────────────
225	// JSONL-only sessions 枚举
226	// ─────────────────────────────────────────────────────────────────────────────
227	
228	function countJsonlCandidateQueries(jsonlFile: string): number {
229	  try {
230	    const lines = readFileSync(jsonlFile, "utf-8").split("\n");
231	    let count = 0;
232	    const seenQueryIds = new Set<string>();
233	    for (const line of lines) {
234	      if (!line.trim()) continue;
235	      try {
236	        const rec = JSON.parse(line) as Record<string, unknown>;
237	        // promptId 出现一次 = 一次 query boundary
238	        const pid = rec["promptId"] as string | undefined;
239	        if (pid && !seenQueryIds.has(pid)) {
240	          seenQueryIds.add(pid);
241	          count++;
242	        }
243	      } catch { /* skip */ }
244	    }
245	    return count;
246	  } catch {
247	    return 0;
248	  }
249	}
250	
251	function scanJsonlOnlySessions(proxySessionIds: Set<string>): DiscoveredJsonlSession[] {
252	  if (!existsSync(CLAUDE_PROJECTS_DIR)) return [];
253	
254	  const result: DiscoveredJsonlSession[] = [];
255	  const projectDirs = readdirSync(CLAUDE_PROJECTS_DIR, { withFileTypes: true })
256	    .filter((e) => e.isDirectory())
257	    .map((e) => join(CLAUDE_PROJECTS_DIR, e.name));
258	
259	  for (const dir of projectDirs) {
260	    const files = readdirSync(dir).filter((f) => f.endsWith(".jsonl"));
261	    for (const f of files) {
262	      const sessionId = f.replace(/\.jsonl$/, "");
263	      if (proxySessionIds.has(sessionId)) continue;  // 已被 proxy 覆盖
264	      const jsonlFile = join(dir, f);
265	      const candidateQueryCount = countJsonlCandidateQueries(jsonlFile);
266	      result.push({
267	        sessionId,
268	        jsonlFile,
269	        agentKind: "claude-code",  // 默认假设，后续可从 JSONL 推断
270	        candidateQueryCount,
271	      });
272	    }
273	  }
274	
275	  return result;
276	}
277	
278	// ─────────────────────────────────────────────────────────────────────────────
279	// 主入口：普通本地模式 discovery
280	// ─────────────────────────────────────────────────────────────────────────────
281	
282	export async function discoverLocal(opts?: {
283	  trafficFile?: string;
284	  sinceTs?: string;
285	}): Promise<DiscoveryResult> {
286	  const proxyRecords = await scanProxyRecords(opts);
287	
288	  const matchedProxyJsonl: DiscoveryResult["matchedProxyJsonl"] = [];
289	  const proxyWithoutJsonl: DiscoveredProxyRecord[] = [];
290	  const proxySessionIds = new Set<string>();
291	
292	  for (const proxy of proxyRecords) {
293	    proxySessionIds.add(proxy.sessionId);
294	    const jsonlFile = findJsonlForSession(proxy.sessionId);
295	    if (jsonlFile) {
296	      matchedProxyJsonl.push({ proxy, jsonlFile });
297	    } else {
298	      proxyWithoutJsonl.push(proxy);
299	    }
300	  }
301	
302	  const jsonlOnlySessions = scanJsonlOnlySessions(proxySessionIds);
303	  const jsonlOnlyCandidateQueries = jsonlOnlySessions.reduce(
304	    (s, x) => s + x.candidateQueryCount, 0,
305	  );
306	
307	  return {
308	    discoveredProxyQueries: proxyRecords,
309	    proxyWithoutJsonl,
310	    matchedProxyJsonl,
311	    jsonlOnlySessions,
312	    jsonlOnlyCandidateQueries,
313	  };
314	}
315	
316	// ─────────────────────────────────────────────────────────────────────────────
317	// Fixture 模式 discovery（用 server/test/fixtures 数据）
318	// ─────────────────────────────────────────────────────────────────────────────
319	
320	export function discoverFixtures(fixtureNames?: string[]): DiscoveryResult {
321	  const names = fixtureNames ?? VALID_FIXTURE_NAMES;
322	  const matchedProxyJsonl: DiscoveryResult["matchedProxyJsonl"] = [];
323	  const proxyWithoutJsonl: DiscoveredProxyRecord[] = [];
324	
325	  for (const name of names) {
326	    const proxyFile = join(FIXTURE_BASE, name, "proxy-request.json");
327	    const jsonlFile = join(FIXTURE_BASE, name, "session.jsonl");
328	
329	    if (!existsSync(proxyFile)) continue;
330	
331	    let raw: Record<string, unknown>;
332	    try {
333	      raw = JSON.parse(readFileSync(proxyFile, "utf-8")) as Record<string, unknown>;
334	    } catch {
335	      continue;
336	    }
337	
338	    const ts = (raw["ts"] as string | undefined) ?? new Date().toISOString();
339	    const tsDigits = ts.replace(/[^0-9]/g, "");
340	    const sessionId = `fixture-${name}`;
341	    const queryId = `query-${tsDigits}`;
342	    const key: QueryKey = { agentKind: "claude-code", sessionId, queryId };
343	    const hash = queryKeyHash(key);
344	
345	    const proxy: DiscoveredProxyRecord = {
346	      queryKey: key,
347	      queryKeyHash: hash,
348	      proxySourceFile: proxyFile,
349	      trafficLine: 0,
350	      timestamp: ts,
351	      sessionId,
352	      agentKind: "claude-code",
353	      raw,
354	    };
355	
356	    if (existsSync(jsonlFile)) {
357	      matchedProxyJsonl.push({ proxy, jsonlFile });
358	    } else {
359	      proxyWithoutJsonl.push(proxy);
360	    }
361	  }
362	
363	  return {
364	    discoveredProxyQueries: [
365	      ...matchedProxyJsonl.map((m) => m.proxy),
366	      ...proxyWithoutJsonl,
367	    ],
368	    proxyWithoutJsonl,
369	    matchedProxyJsonl,
370	    jsonlOnlySessions: [],
371	    jsonlOnlyCandidateQueries: 0,
372	  };
373	}
