1	// Audit Pipeline
2	// 对每个 proxy+jsonl 匹配的 query 运行完整 reconciliation → scorecard → char diff
3	//
4	// 调用链（与 context-char-diff.ts 相同，不重复发明）：
5	//   parseClaudeProxyRequest → inferClaudeProxyAttributions
6	//   → parseClaudeJsonlMutations → reconstructExpectedClaudeContext
7	//   → reconcileClaudeContext → computeCharDiff → renderCharDiffHtml
8	
9	import { readFileSync, existsSync } from "node:fs";
10	import { join } from "node:path";
11	import { parseClaudeProxyRequest } from "../proxy-snapshot-parser";
12	import type { ProxyRequestInput } from "../proxy-snapshot-parser";
13	import { inferClaudeProxyAttributions } from "../proxy-attribution";
14	import { parseClaudeJsonlMutations } from "../jsonl-mutation-parser";
15	import { reconstructExpectedClaudeContext } from "../expected-context-reconstructor";
16	import { reconcileClaudeContext } from "../reconciliation-engine";
17	import { computeCharDiff } from "../debug/char-diff";
18	import { renderCharDiffHtml } from "../debug/render-char-diff-html";
19	import type { ReconciliationReport } from "../types";
20	import type { CharDiffReport } from "../debug/char-diff";
21	import { computeScorecard } from "./scorecard";
22	import type {
23	  DiscoveredProxyRecord,
24	  PipelineResult,
25	  QueryKey,
26	} from "./types";
27	import { queryKeyHash } from "./paths";
28	
29	export interface PipelineInput {
30	  proxy: DiscoveredProxyRecord;
31	  jsonlFile: string | null;  // null → proxy_without_jsonl
32	}
33	
34	export interface PipelineOutputData {
35	  report: ReconciliationReport;
36	  diff: CharDiffReport;
37	  diffHtml: string;
38	  attributions: import("../types").ProxySegmentAttribution[];
39	  reqBody: Record<string, unknown>;
40	}
41	
42	// proxy text 反查（复用 context-char-diff.ts 的同逻辑）
43	function proxyTextForSeg(
44	  seg: import("../types").ContextSegment,
45	  reqBody: Record<string, unknown>,
46	): string | undefined {
47	  for (const ref of seg.sourceRefs) {
48	    if (ref.kind !== "proxy" || !ref.proxy.jsonPath) continue;
49	    const path = ref.proxy.jsonPath.startsWith("reqBody.")
50	      ? ref.proxy.jsonPath.slice("reqBody.".length)
51	      : ref.proxy.jsonPath;
52	    const value = walkPath(path, reqBody);
53	    if (value === undefined || value === null) return undefined;
54	    if (typeof value === "object" && !Array.isArray(value)) {
55	      const obj = value as Record<string, unknown>;
56	      if (typeof obj["text"] === "string") return obj["text"] as string;
57	      return JSON.stringify(obj, null, 2);
58	    }
59	    if (typeof value === "string") return value;
60	    return undefined;
61	  }
62	  return undefined;
63	}
64	
65	function walkPath(path: string, root: unknown): unknown {
66	  const tokens = path.split(/\.|\[(\d+)\]/).filter((t) => t !== undefined && t !== "");
67	  let cur: unknown = root;
68	  for (const tok of tokens) {
69	    if (cur === null || cur === undefined) return undefined;
70	    const idx = parseInt(tok, 10);
71	    if (!isNaN(idx)) {
72	      cur = (cur as unknown[])[idx];
73	    } else {
74	      cur = (cur as Record<string, unknown>)[tok];
75	    }
76	  }
77	  return cur;
78	}
79	
80	function injectProxyTexts(
81	  diff: CharDiffReport,
82	  report: ReconciliationReport,
83	  reqBody: Record<string, unknown>,
84	): CharDiffReport {
85	  const proxyById = new Map(report.snapshot.segments.map((s) => [s.id, s]));
86	  const entries = diff.entries.map((entry) => {
87	    if (!entry.proxyTexts?.length) return entry;
88	    const filled = entry.proxyTexts.map((pt) => {
89	      if (pt.text !== undefined) return pt;
90	      const seg = proxyById.get(pt.segmentId);
91	      if (!seg) return pt;
92	      const text = proxyTextForSeg(seg, reqBody);
93	      return text !== undefined ? { ...pt, text } : pt;
94	    });
95	    return { ...entry, proxyTexts: filled };
96	  });
97	  return { ...diff, entries };
98	}
99	
100	// ─────────────────────────────────────────────────────────────────────────────
101	// 主函数
102	// ─────────────────────────────────────────────────────────────────────────────
103	
104	export function runPipeline(input: PipelineInput): PipelineResult {
105	  const { proxy, jsonlFile } = input;
106	  const { queryKey, queryKeyHash: hash, timestamp, proxySourceFile, trafficLine } = proxy;
107	
108	  // proxy_without_jsonl → skipped
109	  if (!jsonlFile || !existsSync(jsonlFile)) {
110	    return {
111	      queryKey,
112	      queryKeyHash: hash,
113	      status: "skipped",
114	      skipReason: "proxy_without_jsonl",
115	      proxySourceRef: `${proxySourceFile}:${trafficLine}`,
116	      timestamp,
117	    };
118	  }
119	
120	  try {
121	    // 1. 解析 proxy
122	    const raw = proxy.raw;
123	    const reqBody = (raw["reqBody"] as Record<string, unknown>) ?? {};
124	    const proxyInput: ProxyRequestInput = {
125	      ts: raw["ts"] as string | undefined,
126	      startedAt: raw["startedAt"] as string | undefined,
127	      reqHeaders: raw["reqHeaders"] as Record<string, string> | undefined,
128	      reqBody: reqBody as ProxyRequestInput["reqBody"],
129	      _sse_events: raw["_sse_events"] as ProxyRequestInput["_sse_events"],
130	      _traffic_jsonl_line: trafficLine,
131	    };
132	
133	    const snapshot = parseClaudeProxyRequest(proxyInput, {
134	      proxyFile: proxySourceFile,
135	      queryId: queryKey.queryId,
136	    });
137	
138	    // 2. 归因
139	    const snapForAttr = JSON.parse(
140	      JSON.stringify({ ...snapshot, metadata: { ...snapshot.metadata, rawBody: reqBody } }),
141	    ) as typeof snapshot;
142	    const attributions = inferClaudeProxyAttributions(snapForAttr);
143	
144	    // 3. 解析 JSONL
145	    const jsonlRaw = readFileSync(jsonlFile, "utf-8");
146	    const parsed = parseClaudeJsonlMutations(jsonlRaw, { jsonlFile });
147	
148	    // 4. 重建 expected
149	    const proxySegmentsById = new Map(snapshot.segments.map((s) => [s.id, s]));
150	    const expected = reconstructExpectedClaudeContext({
151	      mutations: parsed.mutations,
152	      boundary: {
153	        queryId: queryKey.queryId,
154	        proxyTimestamp: snapshot.timestamp,
155	        sessionId: parsed.sessionId,
156	      },
157	      hasPreSessionActivity: parsed.hasPreSessionActivity,
158	      attributions,
159	      proxySegmentsById,
160	    });
161	
162	    // 5. reconcile
163	    const report = reconcileClaudeContext({ snapshot, attributions, expected });
164	
165	    // 6. char diff
166	    const baseDiff = computeCharDiff(report);
167	    const diff = injectProxyTexts(baseDiff, report, reqBody);
168	    const diffHtml = renderCharDiffHtml(diff);
169	
170	    // 7. scorecard
171	    const scorecard = computeScorecard(queryKey, report, diff);
172	
173	    return {
174	      queryKey,
175	      queryKeyHash: hash,
176	      status: "success",
177	      proxySourceRef: `${proxySourceFile}:${trafficLine}`,
178	      jsonlSourceRef: jsonlFile,
179	      timestamp,
180	      scorecard,
181	      // artifact 路径由 artifact-writer 填入，此处留空
182	    };
183	  } catch (err) {
184	    const message = err instanceof Error ? err.message : String(err);
185	    const stack = err instanceof Error ? err.stack : undefined;
186	    return {
187	      queryKey,
188	      queryKeyHash: hash,
189	      status: "failed",
190	      error: message,
191	      proxySourceRef: `${proxySourceFile}:${trafficLine}`,
192	      jsonlSourceRef: jsonlFile,
193	      timestamp,
194	    };
195	  }
196	}
197	
198	// 带产出数据的版本（用于 artifact 写入）
199	export function runPipelineWithData(input: PipelineInput): {
200	  result: PipelineResult;
201	  data?: PipelineOutputData;
202	} {
203	  const { proxy, jsonlFile } = input;
204	  const { queryKey, queryKeyHash: hash, timestamp, proxySourceFile, trafficLine } = proxy;
205	
206	  if (!jsonlFile || !existsSync(jsonlFile)) {
207	    return {
208	      result: {
209	        queryKey,
210	        queryKeyHash: hash,
211	        status: "skipped",
212	        skipReason: "proxy_without_jsonl",
213	        proxySourceRef: `${proxySourceFile}:${trafficLine}`,
214	        timestamp,
215	      },
216	    };
217	  }
218	
219	  try {
220	    const raw = proxy.raw;
221	    const reqBody = (raw["reqBody"] as Record<string, unknown>) ?? {};
222	    const proxyInput: ProxyRequestInput = {
223	      ts: raw["ts"] as string | undefined,
224	      startedAt: raw["startedAt"] as string | undefined,
225	      reqHeaders: raw["reqHeaders"] as Record<string, string> | undefined,
226	      reqBody: reqBody as ProxyRequestInput["reqBody"],
227	      _sse_events: raw["_sse_events"] as ProxyRequestInput["_sse_events"],
228	      _traffic_jsonl_line: trafficLine,
229	    };
230	
231	    const snapshot = parseClaudeProxyRequest(proxyInput, {
232	      proxyFile: proxySourceFile,
233	      queryId: queryKey.queryId,
234	    });
235	
236	    const snapForAttr = JSON.parse(
237	      JSON.stringify({ ...snapshot, metadata: { ...snapshot.metadata, rawBody: reqBody } }),
238	    ) as typeof snapshot;
239	    const attributions = inferClaudeProxyAttributions(snapForAttr);
240	
241	    const jsonlRaw = readFileSync(jsonlFile, "utf-8");
242	    const parsed = parseClaudeJsonlMutations(jsonlRaw, { jsonlFile });
243	
244	    const proxySegmentsById = new Map(snapshot.segments.map((s) => [s.id, s]));
245	    const expected = reconstructExpectedClaudeContext({
246	      mutations: parsed.mutations,
247	      boundary: {
248	        queryId: queryKey.queryId,
249	        proxyTimestamp: snapshot.timestamp,
250	        sessionId: parsed.sessionId,
251	      },
252	      hasPreSessionActivity: parsed.hasPreSessionActivity,
253	      attributions,
254	      proxySegmentsById,
255	    });
256	
257	    const report = reconcileClaudeContext({ snapshot, attributions, expected });
258	    const baseDiff = computeCharDiff(report);
259	    const diff = injectProxyTexts(baseDiff, report, reqBody);
260	    const diffHtml = renderCharDiffHtml(diff);
261	    const scorecard = computeScorecard(queryKey, report, diff);
262	
263	    // queryKind 细化：side_query 中命中 session-title rule 的标注为 session_title_side_query
264	    const baseQueryKind = snapshot.request?.queryKind ?? "unknown";
265	    const queryKind = (() => {
266	      if (baseQueryKind !== "side_query") return baseQueryKind;
267	      const hasSessionTitleRule = attributions.some(
268	        (a) => a.ruleId === "claude-code.side-query.session-title.v1",
269	      );
270	      return hasSessionTitleRule ? "session_title_side_query" : "side_query";
271	    })();
272	
273	    return {
274	      result: {
275	        queryKey,
276	        queryKeyHash: hash,
277	        status: "success",
278	        proxySourceRef: `${proxySourceFile}:${trafficLine}`,
279	        jsonlSourceRef: jsonlFile,
280	        timestamp,
281	        scorecard,
282	        queryKind,
283	      },
284	      data: { report, diff, diffHtml, attributions, reqBody },
285	    };
286	  } catch (err) {
287	    const message = err instanceof Error ? err.message : String(err);
288	    return {
289	      result: {
290	        queryKey,
291	        queryKeyHash: hash,
292	        status: "failed",
293	        error: message,
294	        proxySourceRef: `${proxySourceFile}:${trafficLine}`,
295	        jsonlSourceRef: jsonlFile,
296	        timestamp,
297	      },
298	    };
299	  }
300	}
