1	// Scorecard 计算：从 ReconciliationReport + CharDiffReport 提取量化指标
2	// 参考：docs/context-reconstruction-correction.md 的指标定义
3	
4	import type { ReconciliationReport } from "../types";
5	import type { CharDiffReport } from "../debug/char-diff";
6	import type { AuditVerdict, QueryScorecard } from "./types";
7	import { queryKeyHash } from "./paths";
8	import type { QueryKey } from "./types";
9	
10	// verdict 判断阈值（本地常量，不需要配置 UI）
11	const THRESHOLDS = {
12	  // evidenceBackedCoverage 下降超过此值视为 regression
13	  evidenceBackedDropRegression: 0.05,
14	  // unknownProxyChars 上升超过此值视为 regression（绝对字符数）
15	  unknownCharsRiseRegression: 500,
16	  // evidenceBackedCoverage 上升超过此值视为 improvement
17	  evidenceBackedRiseImprovement: 0.02,
18	  // unknownProxyChars 下降超过此值视为 improvement
19	  unknownCharsDropImprovement: 200,
20	  // attributionOnlyProxyChars 下降超过此值视为 improvement（相对 proxyChars 的比例）
21	  attrOnlyDropImprovementRatio: 0.03,
22	  // suspectMatchChars 上升超过此值视为 regression（相对 proxyChars 的比例）
23	  suspectRiseRegressionRatio: 0.05,
24	  // 新 query 的 evidenceBackedCoverage 低于此值 → needs_review
25	  newQueryLowEvidenceCoverage: 0.5,
26	  // evidenceBackedCoverage 上升但 drift 也上升时的 drift 阈值
27	  driftRiseNeedsReview: 0.05,
28	};
29	
30	export function computeScorecard(
31	  queryKey: QueryKey,
32	  report: ReconciliationReport,
33	  diff: CharDiffReport,
34	): QueryScorecard {
35	  const { coverage } = report;
36	
37	  const proxyChars = coverage.proxyChars;
38	  const evidenceBackedProxyChars = Math.round((coverage.evidenceBackedCoverage ?? 0) * proxyChars);
39	  const attributionOnlyProxyChars = Math.round(
40	    (coverage.attributionOnlyGap ?? 0) * proxyChars,
41	  );
42	  const attributedProxyChars = Math.round((coverage.attributionCoverage ?? 0) * proxyChars);
43	  const unknownProxyChars = coverage.unexplainedProxyChars;
44	
45	  // suspect match chars 从 char diff summary 取
46	  const suspectMatchChars = diff.summary.suspectMatchChars;
47	
48	  // alignedAuditedChars = evidence-backed matched chars（matched_exact + matched_char_diff）
49	  const alignedAuditedChars =
50	    diff.summary.totalProxyChars > 0
51	      ? Math.round(diff.summary.evidenceBackedCoverage * diff.summary.totalProxyChars)
52	      : evidenceBackedProxyChars;
53	
54	  // alignedTextDriftChars = evidence-backed matched 中的字符漂移绝对值之和
55	  const alignedTextDriftChars = diff.summary.totalCharDriftAbsolute;
56	
57	  // falseReliableMatchCount：suspect_match finding 数（heuristic 无锚点匹配）
58	  const falseReliableMatchCount = diff.summary.suspectMatch;
59	
60	  // prefixIncompleteCount：report 的 expected metadata 中 prefixIncomplete 标记
61	  const prefixIncompleteCount =
62	    report.expected?.metadata?.prefixIncomplete ? 1 : 0;
63	
64	  // sourceTextUnavailableCount：diff 中 expected_only 且无文本内容的条目
65	  const sourceTextUnavailableCount = diff.entries.filter(
66	    (e) => e.kind === "expected_only" && !e.expectedTexts?.some((t) => t.text),
67	  ).length;
68	
69	  // 覆盖率比例
70	  const attributionCoverage = coverage.attributionCoverage ?? 0;
71	  const evidenceBackedCoverage = coverage.evidenceBackedCoverage ?? 0;
72	  const attributionOnlyRatio = coverage.attributionOnlyGap ?? 0;
73	  const alignedTextDriftRatio = coverage.alignedTextDrift ?? 0;
74	
75	  const hash = queryKeyHash(queryKey);
76	
77	  // 初始 verdict（无 baseline 对比，单次 run 的基础判断）
78	  const { verdict, reasons } = classifySingleRunVerdict({
79	    evidenceBackedCoverage,
80	    unknownProxyChars,
81	    falseReliableMatchCount,
82	    prefixIncompleteCount,
83	    sourceTextUnavailableCount,
84	    suspectMatchChars,
85	    proxyChars,
86	    alignedTextDriftRatio,
87	  });
88	
89	  return {
90	    queryKey: `${queryKey.agentKind}/${queryKey.sessionId}/${queryKey.queryId}`,
91	    queryKeyHash: hash,
92	    proxyChars,
93	    attributedProxyChars,
94	    evidenceBackedProxyChars,
95	    attributionOnlyProxyChars,
96	    unknownProxyChars,
97	    suspectMatchChars,
98	    alignedAuditedChars,
99	    alignedTextDriftChars,
100	    falseReliableMatchCount,
101	    prefixIncompleteCount,
102	    sourceTextUnavailableCount,
103	    attributionCoverage,
104	    evidenceBackedCoverage,
105	    attributionOnlyRatio,
106	    alignedTextDriftRatio,
107	    verdict,
108	    reasons,
109	    generatedAt: new Date().toISOString(),
110	  };
111	}
112	
113	// 无 baseline 时的单次 run verdict（新 query 或首次 run）
114	function classifySingleRunVerdict(m: {
115	  evidenceBackedCoverage: number;
116	  unknownProxyChars: number;
117	  falseReliableMatchCount: number;
118	  prefixIncompleteCount: number;
119	  sourceTextUnavailableCount: number;
120	  suspectMatchChars: number;
121	  proxyChars: number;
122	  alignedTextDriftRatio: number;
123	}): { verdict: AuditVerdict; reasons: string[] } {
124	  const reasons: string[] = [];
125	
126	  if (m.falseReliableMatchCount > 0) {
127	    reasons.push(`suspect_match x${m.falseReliableMatchCount}`);
128	  }
129	  if (m.prefixIncompleteCount > 0) {
130	    reasons.push("prefix_incomplete");
131	  }
132	  if (m.sourceTextUnavailableCount > 0) {
133	    reasons.push(`source_text_unavailable x${m.sourceTextUnavailableCount}`);
134	  }
135	  if (m.evidenceBackedCoverage < THRESHOLDS.newQueryLowEvidenceCoverage) {
136	    reasons.push(
137	      `low_evidence_backed_coverage (${(m.evidenceBackedCoverage * 100).toFixed(1)}%)`,
138	    );
139	  }
140	
141	  const needsReview =
142	    m.evidenceBackedCoverage < THRESHOLDS.newQueryLowEvidenceCoverage ||
143	    m.prefixIncompleteCount > 0 ||
144	    m.sourceTextUnavailableCount > 0;
145	
146	  return {
147	    verdict: needsReview ? "needs_review" : "ok",
148	    reasons,
149	  };
150	}
151	
152	// ─────────────────────────────────────────────────────────────────────────────
153	// Delta 分类（current vs previous baseline）
154	// ─────────────────────────────────────────────────────────────────────────────
155	
156	export function classifyDelta(
157	  current: QueryScorecard,
158	  previous: QueryScorecard | undefined,
159	  isNew: boolean,
160	): { verdict: AuditVerdict; reasons: string[] } {
161	  if (isNew || !previous) {
162	    // 新 query：直接按指标判断，不信任 current.verdict（可能是旧 run 写入的值）
163	    const reasons: string[] = [];
164	    if (isNew) reasons.push("new_query");
165	    if (current.prefixIncompleteCount > 0) reasons.push("prefix_incomplete");
166	    if (current.sourceTextUnavailableCount > 0)
167	      reasons.push(`source_text_unavailable x${current.sourceTextUnavailableCount}`);
168	    if (current.evidenceBackedCoverage < THRESHOLDS.newQueryLowEvidenceCoverage) {
169	      reasons.push(`low_evidence_backed_coverage (${(current.evidenceBackedCoverage * 100).toFixed(1)}%)`);
170	    }
171	    // 新 query 默认 needs_review；高覆盖率且无异常时仍是 needs_review（保守）
172	    return { verdict: "needs_review", reasons };
173	  }
174	
175	  const reasons: string[] = [];
176	
177	  const ebDelta = current.evidenceBackedCoverage - previous.evidenceBackedCoverage;
178	  const unknownDelta = current.unknownProxyChars - previous.unknownProxyChars;
179	  const attrOnlyDelta =
180	    (current.attributionOnlyProxyChars - previous.attributionOnlyProxyChars) /
181	    Math.max(current.proxyChars, 1);
182	  const suspectDelta =
183	    (current.suspectMatchChars - previous.suspectMatchChars) /
184	    Math.max(current.proxyChars, 1);
185	  const driftDelta = current.alignedTextDriftRatio - previous.alignedTextDriftRatio;
186	
187	  // regression 条件（任意一个触发即 regression）
188	  const isRegression =
189	    current.falseReliableMatchCount > 0 ||
190	    ebDelta < -THRESHOLDS.evidenceBackedDropRegression ||
191	    unknownDelta > THRESHOLDS.unknownCharsRiseRegression ||
192	    attrOnlyDelta > 0.05 ||
193	    suspectDelta > THRESHOLDS.suspectRiseRegressionRatio;
194	
195	  // improvement 条件（任意一个满足，且无 regression）
196	  const isImprovement =
197	    !isRegression &&
198	    (ebDelta > THRESHOLDS.evidenceBackedRiseImprovement ||
199	      unknownDelta < -THRESHOLDS.unknownCharsDropImprovement ||
200	      attrOnlyDelta < -THRESHOLDS.attrOnlyDropImprovementRatio);
201	
202	  // needs_review（上升但有 drift 暴露 / 已知标记）
203	  const isNeedsReview =
204	    current.prefixIncompleteCount > 0 ||
205	    current.sourceTextUnavailableCount > 0 ||
206	    (ebDelta > 0 && driftDelta > THRESHOLDS.driftRiseNeedsReview);
207	
208	  if (isRegression) {
209	    if (current.falseReliableMatchCount > 0)
210	      reasons.push(`suspect_match x${current.falseReliableMatchCount}`);
211	    if (ebDelta < -THRESHOLDS.evidenceBackedDropRegression)
212	      reasons.push(`evidence_backed_drop ${(ebDelta * 100).toFixed(1)}%`);
213	    if (unknownDelta > THRESHOLDS.unknownCharsRiseRegression)
214	      reasons.push(`unknown_chars_rise +${unknownDelta}`);
215	    if (attrOnlyDelta > 0.05)
216	      reasons.push(`attribution_only_rise ${(attrOnlyDelta * 100).toFixed(1)}%`);
217	    if (suspectDelta > THRESHOLDS.suspectRiseRegressionRatio)
218	      reasons.push(`suspect_chars_rise ${(suspectDelta * 100).toFixed(1)}%`);
219	    return { verdict: "regression", reasons };
220	  }
221	
222	  if (isNeedsReview) {
223	    if (current.prefixIncompleteCount > 0) reasons.push("prefix_incomplete");
224	    if (current.sourceTextUnavailableCount > 0)
225	      reasons.push(`source_text_unavailable x${current.sourceTextUnavailableCount}`);
226	    if (ebDelta > 0 && driftDelta > THRESHOLDS.driftRiseNeedsReview)
227	      reasons.push(`drift_rise ${(driftDelta * 100).toFixed(1)}%`);
228	    return { verdict: "needs_review", reasons };
229	  }
230	
231	  if (isImprovement) {
232	    if (ebDelta > THRESHOLDS.evidenceBackedRiseImprovement)
233	      reasons.push(`evidence_backed_rise +${(ebDelta * 100).toFixed(1)}%`);
234	    if (unknownDelta < -THRESHOLDS.unknownCharsDropImprovement)
235	      reasons.push(`unknown_chars_drop ${unknownDelta}`);
236	    if (attrOnlyDelta < -THRESHOLDS.attrOnlyDropImprovementRatio)
237	      reasons.push(`attribution_only_drop ${(attrOnlyDelta * 100).toFixed(1)}%`);
238	    return { verdict: "improvement", reasons };
239	  }
240	
241	  // 完全相同
242	  if (
243	    current.evidenceBackedCoverage === previous.evidenceBackedCoverage &&
244	    current.unknownProxyChars === previous.unknownProxyChars &&
245	    current.suspectMatchChars === previous.suspectMatchChars
246	  ) {
247	    return { verdict: "unchanged", reasons: [] };
248	  }
249	
250	  return { verdict: "ok", reasons: [] };
251	}
