1	#!/usr/bin/env bun
2	// context-audit.ts — Context Audit Runner CLI
3	//
4	// 用法：
5	//   bun run context:audit                    # 扫描本地所有 proxy records
6	//   bun run context:audit --fixtures         # 用 test fixtures 快速跑通调测 loop
7	//   bun run context:audit --all-local        # 明确指定扫描全量本地数据
8	//   bun run context:audit --since-last       # 只处理上次 run 以来的新 proxy records
9	//   bun run context:audit --baseline <runId> # 对比指定 baseline 而非 latest
10	//   bun run context:audit:mark-baseline <runId>
11	//   bun run context:audit clear              # 清除所有 audit 产物（不删 proxy/jsonl 原始数据）
12	//   bun run context:audit clear --keep <N>   # 保留最近 N 个 run，清除其余
13	
14	import { existsSync, readFileSync, rmSync, readdirSync } from "node:fs";
15	import { join } from "node:path";
16	
17	import { makeRunId, runDir, AUDIT_HOME, RUNS_DIR, LATEST_JSON, BASELINE_JSON } from "../server/src/context-ledger/audit/paths";
18	import { discoverFixtures, discoverLocal } from "../server/src/context-ledger/audit/discovery";
19	import { runPipelineWithData } from "../server/src/context-ledger/audit/pipeline";
20	import {
21	  ensureAuditDirs,
22	  loadBaselineIndex,
23	  writeQueryArtifacts,
24	  writeIndex,
25	  writeRunJson,
26	  updateLatestPointer,
