33	
34	// ─────────────────────────────────────────────────────────────────────────────
35	// 参数解析
36	// ─────────────────────────────────────────────────────────────────────────────
37	
38	const args = process.argv.slice(2);
39	
40	// clear 子命令：清除 audit 产物，不删除 proxy/jsonl 原始数据
41	if (args[0] === "clear") {
42	  const keepIdx = args.indexOf("--keep");
43	  const keepN = keepIdx !== -1 ? parseInt(args[keepIdx + 1] ?? "0", 10) : 0;
44	
45	  if (!existsSync(RUNS_DIR)) {
46	    console.log("没有 audit 产物（runs/ 目录不存在），无需清理。");
47	    process.exit(0);
48	  }
49	
50	  // 按字典序（= 时间序）列出所有 run 目录
51	  const allRuns = readdirSync(RUNS_DIR)
52	    .filter((name) => existsSync(join(RUNS_DIR, name, "run.json")))
53	    .sort();  // runId 格式含 ISO 时间戳，字典序 = 时间序
54	
55	  if (allRuns.length === 0) {
56	    console.log("runs/ 为空，无需清理。");
57	    process.exit(0);
58	  }
59	
60	  const keep = Math.max(0, keepN);
61	  const toDelete = keep > 0 ? allRuns.slice(0, allRuns.length - keep) : allRuns;
62	  const toKeep = keep > 0 ? allRuns.slice(allRuns.length - keep) : [];
63	
64	  if (toDelete.length === 0) {
65	    console.log(`已有 ${allRuns.length} 个 run，--keep ${keep} 无需删除任何内容。`);
66	    process.exit(0);
67	  }
68	
69	  console.log(`将删除 ${toDelete.length} 个 run（保留 ${toKeep.length} 个）：`);
70	  for (const r of toDelete) console.log(`  - ${r}`);
71	  if (toKeep.length > 0) {
72	    console.log(`保留：`);
73	    for (const r of toKeep) console.log(`  + ${r}`);
74	  }
75	
76	  for (const r of toDelete) {
77	    rmSync(join(RUNS_DIR, r), { recursive: true, force: true });
78	  }
79	
80	  // latest.json / baseline.json：若指向被删除的 run，清除指针
81	  if (existsSync(LATEST_JSON)) {
82	    try {
83	      const p = JSON.parse(readFileSync(LATEST_JSON, "utf-8")) as { runId: string };
84	      if (toDelete.includes(p.runId)) {
85	        rmSync(LATEST_JSON, { force: true });
86	        console.log("已清除 latest.json（指向的 run 已删除）");
87	      }
88	    } catch { /* 损坏的 json，直接删 */ rmSync(LATEST_JSON, { force: true }); }
89	  }
90	  if (existsSync(BASELINE_JSON)) {
91	    try {
92	      const p = JSON.parse(readFileSync(BASELINE_JSON, "utf-8")) as { runId: string };
93	      if (toDelete.includes(p.runId)) {
94	        rmSync(BASELINE_JSON, { force: true });
95	        console.log("已清除 baseline.json（指向的 run 已删除）");
96	      }
97	    } catch { rmSync(BASELINE_JSON, { force: true }); }
98	  }
99	
100	  console.log(`✓ 清理完成（${toDelete.length} 个 run 已删除）`);
101	  process.exit(0);
102	}
103	
104	// mark-baseline 子命令
105	if (args[0] === "mark-baseline") {
106	  const runId = args[1];
107	  if (!runId) {
108	    console.error("用法：bun run context:audit:mark-baseline <runId>");
109	    process.exit(1);
