119	}
120	
121	const mode: AuditRunRecord["mode"] = args.includes("--fixtures")
122	  ? "fixtures"
123	  : args.includes("--since-last")
124	  ? "since-last"
125	  : "all-local";
126	
127	// --baseline 指定对比 run
128	let baselineRunId: string | undefined;
129	const baselineIdx = args.indexOf("--baseline");
130	if (baselineIdx !== -1 && args[baselineIdx + 1]) {
131	  baselineRunId = args[baselineIdx + 1];
132	} else {
133	  // 默认：先找 baseline.json，再找 latest run（fixture 模式同样支持 delta 比较）
134	  baselineRunId = readBaselineRunId() ?? readLatestRunId();
135	}
136	
137	// ─────────────────────────────────────────────────────────────────────────────
138	// Discovery
139	// ─────────────────────────────────────────────────────────────────────────────
140	
141	console.log(`\nContext Audit Runner`);
142	console.log(`mode: ${mode}`);
143	console.log(`baseline: ${baselineRunId ?? "(none)"}`);
144	console.log(`Discovering...`);
