1	// audit-run.md 和 index.html 生成器
2	
3	import { writeFileSync } from "node:fs";
4	import { join } from "node:path";
5	import { runDir } from "./paths";
6	import type { AuditIndexEntry, AuditRunRecord } from "./types";
7	
8	// ─────────────────────────────────────────────────────────────────────────────
9	// audit-run.md
10	// ─────────────────────────────────────────────────────────────────────────────
11	
12	export function writeAuditRunMd(runId: string, run: AuditRunRecord, entries: AuditIndexEntry[]): void {
13	  const regressions = entries
14	    .filter((e) => e.changeClass === "regressed")
15	    .sort((a, b) => {
16	      // 按 suspectMatchChars + unknownProxyChars 降序（越大越需要优先看）
17	      return 0;  // 简化：保持 index 顺序
18	    });
19	  const needsReview = entries.filter((e) => e.changeClass === "needs_review");
20	  const proxyWithoutJsonl = entries.filter((e) => e.reasons.includes("proxy_without_jsonl"));
21	  const newQueries = entries.filter((e) => e.changeClass === "new");
22	
23	  const lines: string[] = [
24	    `# Context Audit Run`,
25	    ``,
26	    `- **runId**: \`${run.runId}\``,
27	    `- **createdAt**: ${run.createdAt}`,
28	    `- **baselineRunId**: ${run.baselineRunId ?? "(none — first run)"}`,
29	    `- **mode**: ${run.mode}`,
30	    ``,
31	    `## Discovery Summary`,
32	    ``,
33	    `| 指标 | 数量 |`,
34	    `|------|------|`,
35	    `| discoveredProxyQueries | ${run.discoveredProxyQueries} |`,
36	    `| matchedProxyJsonlQueries | ${run.matchedProxyJsonlQueries} |`,
37	    `| proxyWithoutJsonlQueries | ${run.proxyWithoutJsonlQueries} |`,
38	    `| jsonlOnlySessions | ${run.jsonlOnlySessions} |`,
39	    `| jsonlOnlyCandidateQueries | ${run.jsonlOnlyCandidateQueries} |`,
40	    ``,
41	    `## Delta Summary`,
42	    ``,
43	    `| 对比项 | 数量 |`,
44	    `|--------|------|`,
45	    `| previousQueries | ${run.previousQueries} |`,
46	    `| currentQueries | ${run.currentQueries} |`,
47	    `| newQueries | ${run.newQueries} |`,
48	    `| removedQueries | ${run.removedQueries} |`,
49	    `| commonQueries | ${run.commonQueries} |`,
50	    ``,
51	    `## Verdict Summary`,
52	    ``,
53	    `| Verdict | 数量 |`,
54	    `|---------|------|`,
55	    `| improved | ${run.improvedQueries} |`,
56	    `| regressed | ${run.regressedQueries} |`,
57	    `| needs_review | ${run.needsReviewQueries} |`,
58	    `| unchanged | ${run.unchangedQueries} |`,
59	    `| skipped | ${run.skippedQueries} |`,
60	    `| failed | ${run.failedQueries} |`,
61	    ``,
62	  ];
63	
64	  // Top regressions
65	  if (regressions.length > 0) {
66	    lines.push(`## Top Regressions`, ``);
67	    lines.push(`| queryKey | reason | char diff |`);
68	    lines.push(`|---------|--------|-----------|`);
69	    for (const e of regressions.slice(0, 10)) {
70	      const reasons = e.reasons.join(", ");
71	      const diffLink = e.charDiffHtmlPath ? `[diff](${e.charDiffHtmlPath})` : "-";
72	      lines.push(`| ${e.queryKey.sessionId}/${e.queryKey.queryId} | ${reasons} | ${diffLink} |`);
73	    }
74	    lines.push(``);
75	  }
76	
77	  // Top needs review
78	  if (needsReview.length > 0) {
79	    lines.push(`## Top Needs Review`, ``);
80	    lines.push(`| queryKey | reason | report | char diff |`);
81	    lines.push(`|---------|--------|--------|-----------|`);
82	    for (const e of needsReview.slice(0, 10)) {
83	      const reasons = e.reasons.join(", ");
84	      const reportLink = e.reportPath ? `[report](${e.reportPath})` : "-";
85	      const diffLink = e.charDiffHtmlPath ? `[diff](${e.charDiffHtmlPath})` : "-";
86	      lines.push(`| ${e.queryKey.sessionId}/${e.queryKey.queryId} | ${reasons} | ${reportLink} | ${diffLink} |`);
87	    }
88	    lines.push(``);
89	  }
90	
91	  // New queries
92	  if (newQueries.length > 0) {
93	    lines.push(`## New Proxy Queries (${newQueries.length})`, ``);
94	    for (const e of newQueries.slice(0, 5)) {
95	      lines.push(`- \`${e.queryKey.sessionId}/${e.queryKey.queryId}\` — ${e.verdict}`);
96	    }
97	    if (newQueries.length > 5) lines.push(`- ...and ${newQueries.length - 5} more`);
98	    lines.push(``);
99	  }
100	
101	  // Proxy without JSONL
102	  if (proxyWithoutJsonl.length > 0) {
103	    lines.push(`## Proxy Without JSONL (${proxyWithoutJsonl.length})`, ``);
104	    for (const e of proxyWithoutJsonl.slice(0, 5)) {
105	      lines.push(`- \`${e.proxySourceRef}\` sessionId=${e.sessionId}`);
106	    }
107	    lines.push(``);
108	  }
109	
110	  // Proxy coverage note
111	  lines.push(`## Proxy Coverage Note`, ``);
112	  lines.push(
113	    `本次 audit 以 proxy-first 口径进行。proxy 记录是 ground truth，`
114	    + `只有同时找到 proxy 和 JSONL 的 query 才进入完整 reconciliation 流程。`,
115	  );
116	  lines.push(``);
117	  lines.push(
118	    `JSONL-only 会话（共 ${run.jsonlOnlySessions} 个，约 ${run.jsonlOnlyCandidateQueries} 条候选 query）`
119	    + `不代表失败，只表示对应的 API 请求没有经过本地 proxy 记录，无法做 proxy ground truth 对账。`,
120	  );
121	  lines.push(``);
122	  if (run.proxyWithoutJsonlQueries > 0) {
123	    lines.push(
124	      `proxy_without_jsonl（${run.proxyWithoutJsonlQueries} 条）`
125	      + `表示 proxy 记录了请求，但找不到对应 JSONL session，`
126	      + `可能原因：代理安装后 Claude Code 尚未写入 session，或 session 在另一目录。`,
127	    );
128	    lines.push(``);
129	  }
130	
131	  // Next actions
132	  lines.push(`## Next Action Suggestions`, ``);
133	  if (run.regressedQueries > 0) {
134	    lines.push(`- **Regression detected**: 检查 proxy-attribution / reconciliation-engine 的 M4 heuristic 是否引入了新的 suspect_match。`);
135	    lines.push(`- 参考路径：\`server/src/context-ledger/proxy-attribution.ts\` / \`reconciliation-engine.ts\``);
136	  }
137	  if (run.needsReviewQueries > 0) {
138	    lines.push(`- **Needs review**: 检查 expected-context-reconstructor 的 U1-U5 未实现规则是否影响了 evidenceBackedCoverage。`);
139	  }
140	  lines.push(`- **No automatic code modification**: 本 audit 仅生成报告，不自动修改 parser/reconstructor/reconciliation 核心代码。`);
141	  lines.push(``);
142	
143	  writeFileSync(join(runDir(runId), "audit-run.md"), lines.join("\n"), "utf-8");
144	}
