147	// index.html（自包含静态页面）
148	// ─────────────────────────────────────────────────────────────────────────────
149	
150	export function writeIndexHtml(runId: string, run: AuditRunRecord, entries: AuditIndexEntry[]): void {
151	  // 按 LLM 请求时间倒序（最近的在最前）
152	  const sorted = [...entries].sort((a, b) => (b.timestamp ?? "").localeCompare(a.timestamp ?? ""));
153	
154	  const regressions = sorted.filter((e) => e.changeClass === "regressed");
155	  const needsReview = sorted.filter((e) => e.changeClass === "needs_review");
156	  const newEntries = sorted.filter((e) => e.changeClass === "new");
157	  const proxyWithoutJsonl = sorted.filter((e) => e.reasons.includes("proxy_without_jsonl"));
158	  const failed = sorted.filter((e) => e.changeClass === "failed");
159	  const skipped = sorted.filter((e) => e.changeClass === "skipped");
160	
161	  const verdictColor = (v: string): string => {
162	    if (v === "regressed" || v === "regression") return "#ef4444";
163	    if (v === "improved" || v === "improvement") return "#22c55e";
164	    if (v === "needs_review") return "#f59e0b";
165	    if (v === "failed") return "#dc2626";
166	    if (v === "skipped") return "#9ca3af";
167	    if (v === "new") return "#3b82f6";
168	    return "#6b7280";
169	  };
170	
171	  const esc = (s: string): string =>
172	    s.replace(/&/g, "&amp;").replace(/</g, "&lt;").replace(/>/g, "&gt;");
173	
174	  // queryKind → badge 样式
175	  const queryKindBadge = (qk: string | undefined): string => {
176	    if (!qk) return `<span style="color:#475569">?</span>`;
177	    if (qk === "main_session") {
178	      return `<span style="background:#1e3a5f;color:#7dd3fc;padding:1px 6px;border-radius:3px;font-size:10px;font-weight:600">main</span>`;
179	    }
180	    if (qk === "session_title_side_query") {
181	      // session-title 是 Claude Code 标准内置逻辑（initReplBridge.ts count=1/3 触发）
182	      return `<span style="background:#1c1917;color:#a78bfa;padding:1px 6px;border-radius:3px;font-size:10px;font-weight:600" title="generateSessionTitle() — Claude Code 内置，会话首消息后自动触发（count=1/3）">title</span>`;
183	    }
184	    if (qk === "side_query") {
185	      return `<span style="background:#1c1917;color:#94a3b8;padding:1px 6px;border-radius:3px;font-size:10px">side</span>`;
186	    }
187	    return `<span style="color:#475569;font-size:10px">${esc(qk)}</span>`;
188	  };
189	
190	  const renderRow = (e: AuditIndexEntry): string => {
191	    const color = verdictColor(e.changeClass);
192	    const verdict = `<span style="color:${color};font-weight:600">${esc(e.verdict)}</span>`;
193	    const reportLink = e.reportPath ? `<a href="${esc(e.reportPath)}">report</a>` : "";
194	    const diffLink = e.charDiffHtmlPath ? `<a href="${esc(e.charDiffHtmlPath)}">diff</a>` : "";
195	    const scLink = e.scorecardPath ? `<a href="${esc(e.scorecardPath)}">sc</a>` : "";
196	    const attrLink = e.proxyAttributionViewPath
197	      ? `<a href="${esc(e.proxyAttributionViewPath)}" title="proxy → parser → attribution 三列视图" style="color:#8b5cf6">attr</a>`
198	      : "";
199	    const reasons = esc(e.reasons.join(", "));
200	    return `<tr>
201	      <td>${verdict}</td>
202	      <td style="color:${verdictColor(e.changeClass)}">${esc(e.changeClass)}</td>
203	      <td>${queryKindBadge(e.queryKind)}</td>
204	      <td><code>${esc(e.sessionId.slice(0, 8))}…/${esc(e.queryId.slice(0, 20))}</code></td>
205	      <td>${reasons}</td>
206	      <td>${reportLink} ${scLink} ${diffLink} ${attrLink}</td>
207	    </tr>`;
208	  };
209	
210	  const html = `<!DOCTYPE html>
211	<html lang="en">
212	<head>
213	<meta charset="UTF-8">
214	<meta name="viewport" content="width=device-width,initial-scale=1">
215	<title>Context Audit — ${esc(runId)}</title>
216	<style>
217	* { box-sizing: border-box; margin: 0; padding: 0; }
218	body { font-family: ui-monospace, monospace; font-size: 13px; background: #f8fafc; color: #1e293b; padding: 24px; }
219	h1 { font-size: 20px; font-weight: 700; margin-bottom: 8px; }
220	h2 { font-size: 15px; font-weight: 600; margin: 20px 0 8px; }
221	.meta { color: #64748b; margin-bottom: 20px; }
222	.grid { display: grid; grid-template-columns: repeat(auto-fill, minmax(200px, 1fr)); gap: 12px; margin-bottom: 20px; }
223	.card { background: white; border: 1px solid #e2e8f0; border-radius: 8px; padding: 12px; }
224	.card-value { font-size: 22px; font-weight: 700; }
225	.card-label { color: #64748b; font-size: 11px; margin-top: 2px; }
226	table { width: 100%; border-collapse: collapse; background: white; border-radius: 8px; overflow: hidden; border: 1px solid #e2e8f0; }
227	th { background: #f1f5f9; padding: 8px 10px; text-align: left; font-size: 11px; color: #64748b; }
228	td { padding: 7px 10px; border-top: 1px solid #f1f5f9; vertical-align: top; }
229	td a { color: #3b82f6; text-decoration: none; }
230	td a:hover { text-decoration: underline; }
231	.note { background: #fffbeb; border: 1px solid #fcd34d; border-radius: 6px; padding: 10px 14px; margin: 12px 0; color: #92400e; }
232	</style>
233	</head>
234	<body>
235	<h1>Context Audit Run</h1>
236	<div class="meta">
237	  <div>runId: <code>${esc(runId)}</code></div>
238	  <div>createdAt: ${esc(run.createdAt)}</div>
239	  <div>baseline: ${run.baselineRunId ? `<code>${esc(run.baselineRunId)}</code>` : "(none)"}</div>
240	  <div>mode: ${esc(run.mode)}</div>
241	</div>
242	
243	<h2>Run Summary</h2>
244	<div class="grid">
245	  <div class="card"><div class="card-value">${run.discoveredProxyQueries}</div><div class="card-label">proxy discovered</div></div>
246	  <div class="card"><div class="card-value">${run.matchedProxyJsonlQueries}</div><div class="card-label">proxy+jsonl matched</div></div>
247	  <div class="card"><div class="card-value">${run.proxyWithoutJsonlQueries}</div><div class="card-label">proxy without jsonl</div></div>
248	  <div class="card"><div class="card-value">${run.jsonlOnlySessions}</div><div class="card-label">jsonl-only sessions</div></div>
249	  <div class="card"><div class="card-value" style="color:#ef4444">${run.regressedQueries}</div><div class="card-label">regressed</div></div>
250	  <div class="card"><div class="card-value" style="color:#22c55e">${run.improvedQueries}</div><div class="card-label">improved</div></div>
251	  <div class="card"><div class="card-value" style="color:#f59e0b">${run.needsReviewQueries}</div><div class="card-label">needs_review</div></div>
252	  <div class="card"><div class="card-value">${run.unchangedQueries}</div><div class="card-label">unchanged</div></div>
253	  <div class="card"><div class="card-value">${run.skippedQueries}</div><div class="card-label">skipped</div></div>
254	  <div class="card"><div class="card-value" style="color:#dc2626">${run.failedQueries}</div><div class="card-label">failed</div></div>
255	</div>
256	
257	<h2>Query Delta</h2>
258	<div class="grid">
259	  <div class="card"><div class="card-value">${run.previousQueries}</div><div class="card-label">previous</div></div>
260	  <div class="card"><div class="card-value">${run.currentQueries}</div><div class="card-label">current</div></div>
261	  <div class="card"><div class="card-value" style="color:#3b82f6">${run.newQueries}</div><div class="card-label">new</div></div>
262	  <div class="card"><div class="card-value">${run.removedQueries}</div><div class="card-label">removed</div></div>
263	  <div class="card"><div class="card-value">${run.commonQueries}</div><div class="card-label">common</div></div>
264	</div>
265	
266	${regressions.length > 0 ? `
267	<h2>Top Regressions (${regressions.length})</h2>
268	<table>
269	<tr><th>verdict</th><th>changeClass</th><th>type</th><th>session/query</th><th>reasons</th><th>links <span style="color:#8b5cf6;font-weight:400">(attr=三列视图)</span></th></tr>
270	${regressions.map(renderRow).join("\n")}
271	</table>` : ""}
272	
273	${needsReview.length > 0 ? `
274	<h2>Needs Review (${needsReview.length})</h2>
275	<table>
276	<tr><th>verdict</th><th>changeClass</th><th>type</th><th>session/query</th><th>reasons</th><th>links</th></tr>
277	${needsReview.map(renderRow).join("\n")}
278	</table>` : ""}
279	
280	${newEntries.length > 0 ? `
281	<h2>New Proxy Queries (${newEntries.length})</h2>
282	<table>
283	<tr><th>verdict</th><th>changeClass</th><th>type</th><th>session/query</th><th>reasons</th><th>links</th></tr>
284	${newEntries.map(renderRow).join("\n")}
285	</table>` : ""}
286	
287	${proxyWithoutJsonl.length > 0 ? `
288	<h2>Proxy Without JSONL (${proxyWithoutJsonl.length})</h2>
289	<div class="note">proxy 找不到对应 JSONL session，不影响整体 run 成功。可能原因：代理重启、网络绕过代理、历史会话缺失。</div>
290	<table>
291	<tr><th>sessionId</th><th>timestamp</th><th>proxySourceRef</th></tr>
292	${proxyWithoutJsonl.map((e) => `<tr><td><code>${esc(e.sessionId)}</code></td><td>${esc(e.timestamp)}</td><td><code>${esc(e.proxySourceRef)}</code></td></tr>`).join("\n")}
293	</table>` : ""}
294	
295	${failed.length > 0 ? `
296	<h2>Failed Queries (${failed.length})</h2>
297	<table>
298	<tr><th>verdict</th><th>changeClass</th><th>type</th><th>session/query</th><th>reasons</th><th>links</th></tr>
299	${failed.map(renderRow).join("\n")}
300	</table>` : ""}
301	
302	<h2>All Queries (${sorted.length})</h2>
303	<table>
304	<tr><th>verdict</th><th>changeClass</th><th>type</th><th>session/query</th><th>reasons</th><th>links</th></tr>
