1	// 旁路脚本：把 rule-registry 里 exact pattern 在本地 Claude Code 可执行文件中对账。
2	//
3	// 用法：
4	//   bun run scripts/verify-rules-against-cli.ts
5	//   bun run scripts/verify-rules-against-cli.ts --target /path/to/claude-binary
6	//   bun run scripts/verify-rules-against-cli.ts --pattern "literal text" --target /path/to/binary
7	//
8	// 默认 target：
9	//   ~/.local/share/claude/versions/<SUPPORTED_CLAUDE_CODE_VERSION>
10	// 找不到则降级到：
11	//   /usr/local/lib/node_modules/@anthropic-ai/claude-code/cli.js
12	//   ~/.npm/_npx/*/node_modules/@anthropic-ai/claude-code/cli.js
13	//
14	// 设计要点（B1.4）：
15	// - target 文件按 latin1 解码成字符串：每个字节 1:1 映射到 char，substring 搜索 = 字节精确匹配。
16	//   Bun 编译的 Mach-O 二进制里 JS 字面量是连续字节流，这个方法对二进制和明文 cli.js 都奏效。
17	// - 只输出找/找不到 + offset + 短上下文，不做 regex 拟合：
18	//   "exact" rule 的语义就是字面相等，rule 通过 = pattern 在 binary 中存在 ≥1 次。
19	// - 不做自动写回 rule-registry，仅产出表格供人工逐条决定 verifiedFor 是否升级到当前版本。
20	import { readFileSync, existsSync, statSync, readdirSync } from "node:fs";
21	import { join } from "node:path";
22	import { homedir } from "node:os";
23	import {
24	  CONTEXT_LEDGER_RULES,
25	  SUPPORTED_CLAUDE_CODE_VERSION,
26	  type ContextLedgerRule,
27	} from "../server/src/context-ledger/rule-registry";
28	
29	// ── 目标文件定位 ────────────────────────────────────────────────────────────────
30	
31	function resolveTarget(explicit?: string): string {
32	  if (explicit) {
33	    if (!existsSync(explicit)) throw new Error(`target 文件不存在：${explicit}`);
34	    return explicit;
35	  }
36	  // 1. ~/.local/share/claude/versions/<SUPPORTED_CLAUDE_CODE_VERSION>
37	  const versioned = join(homedir(), ".local/share/claude/versions", SUPPORTED_CLAUDE_CODE_VERSION);
38	  if (existsSync(versioned)) return versioned;
39	  // 2. 全局 npm 安装
40	  const global = "/usr/local/lib/node_modules/@anthropic-ai/claude-code/cli.js";
41	  if (existsSync(global)) return global;
42	  // 3. npx 缓存（取最新一个）
43	  const npxRoot = join(homedir(), ".npm/_npx");
44	  if (existsSync(npxRoot)) {
45	    const candidates = readdirSync(npxRoot)
46	      .map((d) => join(npxRoot, d, "node_modules/@anthropic-ai/claude-code/cli.js"))
47	      .filter(existsSync)
48	      .sort((a, b) => statSync(b).mtimeMs - statSync(a).mtimeMs);
49	    if (candidates.length > 0) return candidates[0]!;
50	  }

