14	// runId 格式：2026-04-29T11-10-00.000Z__d4e5f6
15	export function makeRunId(): string {
16	  const ts = new Date().toISOString().replace(/:/g, "-");
17	  const hash = createHash("sha256")
18	    .update(ts + Math.random().toString())
19	    .digest("hex")
20	    .slice(0, 6);
21	  return `${ts}__${hash}`;
22	}
