578	// 每条 attribution 有 ruleId → 找到对应 ContextLedgerRule：
579	//   - section=system 或 section=tools
580	//   - reconstruction.trigger=always_per_query
581	//   - materialization=exact_text：contentPattern 非 null → 生成带 rawHash 的 expected segment
582	//   - materialization=presence/shape/normalized_text：生成不带 rawHash 的 expected segment，
583	//     charCount 从 attribution.charCount 读取（proxy ground truth）
584	// billing_noise 跳过（R6 已过滤）。
585	// 同一 ruleId 若在多个 attribution 里出现（多个 request），只取第一次（dedup by ruleId）。
586	
587	function proxyRawText(
588	  attr: ProxySegmentAttribution,
589	  proxySegmentsById?: Map<string, ContextSegment>,
590	): string | undefined {
591	  if (!proxySegmentsById) return undefined;
592	  for (const sid of attr.proxySegmentIds) {
593	    const text = proxySegmentsById.get(sid)?.rawText;
594	    if (text) return text;
595	  }
