599	function buildSegmentsFromAttributions(
600	  attributions: ProxySegmentAttribution[],
601	  proxySegmentsById?: Map<string, ContextSegment>,
602	): ContextSegment[] {
603	  const segments: ContextSegment[] = [];
604	  const seenRuleIds = new Set<string>();
605	  let order = -100000; // 负数 order 保证排在 messages 段之前，按 proxy 顺序递增
606	
607	  for (const attr of attributions) {
608	    const ruleId = attr.ruleId;
609	    if (!ruleId) continue;
610	    if (seenRuleIds.has(ruleId)) continue;
611	
612	    const rule = getContextLedgerRule(ruleId);
613	    if (!rule) continue;
614	
615	    const recon = rule.reconstruction;
616	    if (!recon) continue;
617	    // trigger 不做过滤——attribution 已在 proxy 里确认这段存在，无论 trigger 类型
618	    // （always_per_query / from_memory / from_harness_state）都意味着"本次请求有这段"。
619	
620	    const emits = recon.emits;
621	    // 只处理 system / tools section；messages 层由 mutations 处理
622	    if (emits.section !== "system" && emits.section !== "tools") continue;
623	    // billing_noise 不生成 expected segment（R6 过滤）
624	    if (emits.category === "billing_noise") continue;
625	
626	    seenRuleIds.add(ruleId);
627	
628	    const charCount = attr.charCount ?? 0;
629	    const sourceRef: SourceRef = {
630	      kind: "harness_rule",
631	      harness: { ruleId, version: rule.verifiedFor ?? "unverified" },
632	      label: `rule:${ruleId}`,
633	    };
634	
635	    const seg: ContextSegment = {
636	      id: `eseg-r9-${ruleId.replace(/[^a-z0-9]/gi, "-")}`,
637	      section: emits.section as SegmentSection,
638	      category: emits.category as SegmentCategory,
639	      label: `${emits.section}/${emits.category} (${ruleId})`,
640	      sourceRefs: [sourceRef],
641	      // system section → role=system；tools section は role 未設定（proxy parser 同様）
642	      ...(emits.section === "system" ? { role: "system" as SegmentRole } : {}),
643	      order: order++,
644	      lifecycle: emits.lifecycle ?? "session",
645	      flags: emits.flags ?? [],
646	      charCount,
647	      tokenEstimate: Math.round(charCount / 4),
648	      metadata: pruneMetadata({ ruleId, sourceMutationId: undefined }),
649	    };
650	
651	    if (recon.materialization === "exact_text") {
652	      if (emits.section === "tools") {
653	        // tools section：rawHash = sha256(整个 tool JSON)，与 proxy-snapshot-parser 口径一致。
654	        // proxy segment 的 rawHash 已经是正确值，直接复用。
655	        const pSeg = proxySegmentsById ? attr.proxySegmentIds.map(id => proxySegmentsById.get(id)).find(Boolean) : undefined;
656	        if (pSeg?.rawHash) seg.rawHash = pSeg.rawHash;
657	        // contentRef 用 rawText（= description）仅供展示，charCount 用 proxy ground truth
658	        const text = proxyRawText(attr, proxySegmentsById);
659	        if (text) seg.contentRef = { kind: "inline", text, charCount: attr.charCount ?? text.length } as ContentRef;
660	      } else {
661	        // system section：rawHash = sha256(rawText = 完整 block 文本)
662	        // contentPattern 含 {placeholder} 时先用 attribution notes 里的动态字段替换
663	        const rawPattern = emits.contentPattern;
664	        const resolvedText = rawPattern
665	          ? resolvePlaceholders(rawPattern, attr.notes ?? [])
666	          : proxyRawText(attr, proxySegmentsById);
