import {
  ContextSegment,
  MutationSourceKind,
  ProxyQuerySnapshot,
  ProxySegmentAttribution,
  SegmentCategory,
  SegmentFlag,
  SegmentLifecycle,
  SegmentSection,
} from "./types";

